#include<bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

CI MAXN=1e5+5;
int n,b[MAXN],x[MAXN],y[MAXN],s[MAXN],ans;
stack<int>st;
signed main(void)
{
    n=read();
    FOR(i,1,n)
    {
        b[i]=read();
        s[i]=s[i-1]+b[i];
    }
    FOR(i,1,n)
    {
        wh(!st.empty()&&b[st.top()]>=b[i])
        {
            st.pop();
        }
        if(st.empty())
        {
            x[i]=0;
        }
        else
        {
            x[i]=st.top();
        }
        st.push(i);
    }
    wh(!st.empty())
    {
        st.pop();
    }
    ROF(i,n,1)
    {
        wh(!st.empty()&&b[st.top()]>=b[i])
        {
            st.pop();
        }
        if(st.empty())
        {
            y[i]=n;
        }
        else
        {
            y[i]=st.top()-1;
        }
        st.push(i);
    }
    FOR(i,1,n)
    {
        ans=max(ans,(s[y[i]]-s[x[i]])*b[i]);
    }
    write(ans);
    return false;
}
